"use client";
import { useState } from "react";
import "./globals.css";

import ProcessForm from "./components/ProcessForm";
import ConfigForm from "./components/ConfigForm";
import AlgorithmSelect from "./components/AlgorithmSelect";
import GanttChart from "./components/GanttChart";
import MetricsTable from "./components/MetricsTable";

export default function SimulatorPage() {
  const [processes, setProcesses] = useState([]);
  const [config, setConfig] = useState({
    quantum: 2,
    sobrecarga_contexto: 1,
    algoritmo: "FCFS",
  });
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);

  async function handleSimulate() {
    setLoading(true);
    try {
      const response = await fetch("/api/simulate", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ...config, processos: processes }),
      });
      if (!response.ok) {
        console.error("Resposta não OK:", response.status);
        const text = await response.text();
        console.error(text);
        setResults(null);
      } else {
        const data = await response.json();
        setResults(data);
      }
    } catch (error) {
      console.error("Erro ao simular:", error);
      setResults(null);
    }
    setLoading(false);
  }

  return (
    <main className="container">
      <div className="card">
        <h1 className="h1">Simulador de Escalonamento</h1>

        <ConfigForm config={config} setConfig={setConfig} />
        <AlgorithmSelect config={config} setConfig={setConfig} />
        <ProcessForm processes={processes} setProcesses={setProcesses} />

        <div style={{ display: "flex", justifyContent: "flex-end", marginTop: 16 }}>
          <button
            onClick={handleSimulate}
            disabled={loading}
            style={{
              padding: "8px 16px",
              borderRadius: 10,
              background: loading ? "#93c5fd" : "var(--accent)",
              color: "white",
              border: "none",
              cursor: loading ? "default" : "pointer",
            }}
          >
            {loading ? "Simulando..." : "Iniciar Simulação"}
          </button>
        </div>
      </div>

      {results && (
        <>
          <div className="card" style={{ marginTop: 20 }}>
            <h2 style={{ margin: 0, fontSize: "1.125rem", fontWeight: 600 }}>Gráfico de Gantt</h2>
            <div style={{ marginTop: 12 }}>
              <GanttChart renders={results.renders} />
            </div>
          </div>

          <div className="card" style={{ marginTop: 20 }}>
            <h2 style={{ margin: 0, fontSize: "1.125rem", fontWeight: 600 }}>Métricas</h2>
            <div style={{ marginTop: 12 }}>
              <MetricsTable metrics={results.metrics} summary={results.summary} />
            </div>
          </div>
        </>
      )}
    </main>
  );
}
